document.querySelectorAll(".tool-logo img, .card-logo img").forEach(function(img){function loaded(){img.classList.add("loaded"),img.parentNode&&img.parentNode.classList.add("loaded")}function failed(){img.classList.add("error"),img.parentNode&&img.parentNode.classList.add("error");var fb=img.parentNode&&img.parentNode.querySelector(".logo-fallback");fb&&(fb.style.display="grid")}img&&(img.complete?(0<img.naturalWidth?loaded:failed)():(img.addEventListener("load",loaded),img.addEventListener("error",failed)))});